@app.template_filter("timeago")
def timeago_filter(timestamp_str):
    """Convert timestamp to '5m ago' style string."""
    try:
        dt = datetime.strptime(str(timestamp_str)[:19], "%Y-%m-%d %H:%M:%S")
        mins = int((datetime.now() - dt).total_seconds() / 60)
        if mins < 1:
            return "Just now"
        if mins < 60:
            return f"{mins}m ago"
        if mins < 1440:
            return f"{mins // 60}h ago"
        return f"{mins // 1440}d ago"
    except Exception:
        return ""


def _safe_int(value, default=0):
    """Convert to int, returning default if value is None or non-numeric."""
    try:
        return int(value)
    except (TypeError, ValueError):
        return default


def _is_local_request():
    """Check if request is from LAN (no auth needed) vs remote (needs auth)."""
    # If CF-Connecting-IP header exists, request came through Cloudflare tunnel = REMOTE
    if request.headers.get("CF-Connecting-IP"):
        return False
    # No CF header = direct access. Check if it's from LAN.
    ip = request.remote_addr or ""
    if ip.startswith("192.168.") or ip.startswith("10.") or ip.startswith("172.") or ip == "127.0.0.1":
        return True
    return False


@app.before_request
def check_remote_auth():
    """Require password for ALL remote (Cloudflare tunnel) access."""
    if _is_local_request():
        return  # LAN users skip auth entirely — Don & Colleen never see login
    # Allow login page, static assets, and API endpoints without auth
    # APIs are used by HLS player, image proxies, SSE, etc.
    if (request.path == "/admin/login"
            or request.path.startswith("/static/")
            or request.path.startswith("/api/")):
        return
    # Check for session auth
    if session.get("remote_auth"):
        return
    # Remote user not authenticated — redirect to login
    return redirect("/admin/login")


@app.route("/admin/login", methods=["GET", "POST"])
def admin_login():
    """Simple password login for remote admin access."""
    if request.method == "POST":
        password = request.form.get("password", "")
        stored = models.get_setting("admin_password") or "family2026"
        if secrets.compare_digest(password, stored):
            session["remote_auth"] = True
            return redirect("/admin")
        return render_template_string(LOGIN_TEMPLATE, error="Wrong password")
    return render_template_string(LOGIN_TEMPLATE, error=None)


