@app.route("/api/next-video")
def api_next_video():
    """Get a random video to auto-play. All genres welcome — the library was curated for them.

    Tries a time-of-day preferred genre first (soft preference, not a filter).
    Validates stream URL before recommending (prevents dead streams).
    Tries up to 5 candidates to find one that works.
    """
    import random as _random
    hour = datetime.now().hour
    if hour < 14:
        preferred = ["Comedy", "Family", "Western"]
    elif hour < 17:
        preferred = ["Western", "Comedy", "Drama", "Crime"]
    else:
        preferred = ["Western", "Family", "Comedy", "Crime"]

    jf = _get_jellyfin()
    if not jf:
        return jsonify({"error": "not configured"}), 400

    def _validate_and_return(item, genre=None):
        """Check stream URL is reachable before recommending."""
        if item.get("type") == "series":
            # Series use shuffle — always valid (picks random episode server-side)
            url = f"/tv/plex/shuffle/{item['id']}"
            result = {"id": item["id"], "title": item.get("title", ""),
                      "type": item.get("type", ""), "url": url}
            if genre:
                result["genre"] = genre
            return result
        # Movie — verify stream URL exists
        try:
            stream_url = jf.get_stream_url(item["id"])
            # Stream URL is a local path — make absolute for validation
            if stream_url.startswith("/"):
                stream_url = f"http://localhost:5000{stream_url}"
            resp = requests.head(stream_url, timeout=5, allow_redirects=True)
            if resp.status_code < 400:
                url = f"/tv/plex/play/{item['id']}"
                result = {"id": item["id"], "title": item.get("title", ""),
                          "type": item.get("type", ""), "url": url}
                if genre:
                    result["genre"] = genre
                return result
        except Exception:
            pass
        return None

    try:
        libs = jf.get_libraries()
        # Try up to 5 random picks, validating each
        for attempt in range(5):
            genre = None
            if attempt < 2 and _random.random() < 0.5:
                genre = _random.choice(preferred)

            for lib in libs:
                items = jf.get_library_items(
                    lib["id"], sort="Random", genre=genre, limit=5)
                for item in items:
                    if item["id"] in _excluded_ids:
                        continue
                    result = _validate_and_return(item, genre)
                    if result:
                        return jsonify(result)
    except Exception:
        pass
    return jsonify({"error": "no content"}), 404


@app.route("/api/next-channel")
def api_next_channel():
    """Get a random time-appropriate Pluto TV channel for auto-play fallback."""
    import random as _random
    hour = datetime.now().hour
    if hour < 14:
        preferred = ["Daytime + Game Shows", "Classic TV", "News + Opinion"]
    elif hour < 17:
        preferred = ["Westerns", "Classic TV", "Comedy", "Drama"]
    else:
        preferred = ["Comedy", "Classic TV", "Westerns", "Drama"]

    try:
        import pluto_tv
        channels, _ = pluto_tv.get_channels()
        if not channels:
            return jsonify({"error": "no channels"}), 404

        # Find channels in preferred categories
        for cat in preferred:
            matching = [ch for ch in channels if ch["category"] == cat]
            if matching:
                ch = _random.choice(matching)
                return jsonify({
                    "id": ch["id"],
                    "name": ch["name"],
                    "category": ch["category"],
                    "url": f"/tv/live/play/{ch['id']}",
                })

        # Fall back to any channel
        ch = _random.choice(channels)
        return jsonify({
            "id": ch["id"],
            "name": ch["name"],
            "url": f"/tv/live/play/{ch['id']}",
        })
    except Exception:
        return jsonify({"error": "pluto unavailable"}), 500


